-- 008_seed_cert_questions.sql
-- Starter cert prep question bank: ~30 CW + ~30 CAWI + ~40 CWI = ~100 questions.
-- Use POST /api/cert/generate at runtime to grow the bank toward the 50/75/150 targets.

insert into cert_prep_questions (cert_level, category, question, option_a, option_b, option_c, option_d, correct_answer, explanation, code_reference, difficulty) values

-- ============================================================
-- CW (Certified Welder) — 30 questions
-- ============================================================
('CW', 'processes', 'Which polarity is normally used for SMAW with E7018 electrodes?', 'DCEN (electrode negative)', 'DCEP (electrode positive)', 'AC only', 'High frequency AC', 'B', 'E7018 is a low-hydrogen iron powder electrode that produces best results on DCEP (electrode positive). DCEN can be used but produces less penetration.', 'AWS A5.1', 'easy'),
('CW', 'processes', 'GMAW (MIG) welding uses what type of electrode?', 'Coated stick', 'Solid or metal-cored continuous wire', 'Tungsten non-consumable', 'Carbon rod', 'B', 'GMAW uses a continuous solid or metal-cored wire fed through the gun. Shielding is provided by an external gas.', 'AWS A3.0', 'easy'),
('CW', 'processes', 'In GTAW, the tungsten electrode is:', 'Consumable', 'Non-consumable', 'Coated with flux', 'Hollow', 'B', 'GTAW uses a non-consumable tungsten electrode. Filler metal, when used, is added separately.', 'AWS A3.0', 'easy'),
('CW', 'safety', 'What is the primary hazard of welding on galvanized steel?', 'Eye damage', 'Zinc oxide fume causing metal fume fever', 'Excessive spatter', 'Arc blow', 'B', 'Heating zinc coatings releases zinc oxide fumes which cause metal fume fever (flu-like symptoms). Always use ventilation and respiratory protection.', 'OSHA 1910.252', 'easy'),
('CW', 'safety', 'What is the minimum recommended shade number for SMAW at 100-200 amps?', 'Shade 8', 'Shade 10', 'Shade 11', 'Shade 13', 'C', 'ANSI Z87.1 recommends a minimum of shade 11 for SMAW at 100-200 amps. Higher amperages require darker shades.', 'ANSI Z49.1', 'easy'),
('CW', 'safety', 'Before welding, the welding area should be cleared of:', 'All combustible materials within 35 feet', 'Combustibles within 10 feet', 'Only paper materials', 'Only liquids', 'A', 'NFPA 51B and AWS Z49.1 require combustibles to be removed within 35 feet, or covered with fire-resistant material.', 'NFPA 51B', 'medium'),
('CW', 'visual_inspection', 'Undercut at the toe of a fillet weld indicates:', 'Proper fusion', 'Excessive heat or improper technique', 'Correct travel angle', 'Insufficient amperage', 'B', 'Undercut is caused by excessive heat, fast travel, improper electrode angle, or arc length too long.', 'AWS D1.1', 'easy'),
('CW', 'visual_inspection', 'Excessive convexity on a fillet weld is undesirable because:', 'It looks unprofessional', 'It creates stress concentration at the toes', 'It uses extra filler metal', 'All of the above', 'D', 'Convex fillet welds waste filler metal, look poor, and create stress concentrations at the weld toe that can lead to fatigue cracking.', 'AWS D1.1', 'medium'),
('CW', 'visual_inspection', 'A weld with visible porosity should be:', 'Always accepted', 'Evaluated against the applicable code', 'Always rejected', 'Ground smooth and ignored', 'B', 'Porosity acceptance depends on size, frequency, and the governing code. Some porosity is acceptable per AWS D1.1 §6.9.', 'AWS D1.1', 'medium'),
('CW', 'processes', 'Shielding gas in GMAW serves primarily to:', 'Protect the molten pool from atmospheric contamination', 'Cool the weld', 'Add alloying elements', 'Increase travel speed', 'A', 'The primary purpose of shielding gas is to displace atmospheric oxygen and nitrogen from the arc and molten pool.', 'AWS A3.0', 'easy'),
('CW', 'processes', 'The most common shielding gas mix for short circuit MIG on carbon steel is:', '100% Argon', '75% Argon / 25% CO2', '100% Helium', '100% Nitrogen', 'B', '75/25 Ar/CO2 is the most common mix for short circuit GMAW on carbon steel. Pure CO2 increases penetration but causes more spatter.', 'AWS A5.32', 'easy'),
('CW', 'processes', 'Stringer beads are preferred over weave beads when:', 'Welding aluminum', 'Maximum heat input is desired', 'Welding high-strength low-alloy steel where heat input must be controlled', 'Welding overhead', 'C', 'Stringer beads minimize heat input and the heat-affected zone, which is critical for HSLA and quenched-and-tempered steels.', 'AWS D1.1', 'medium'),
('CW', 'metallurgy', 'Preheating before welding is done to:', 'Speed up the weld', 'Reduce thermal shock and prevent cracking', 'Save filler metal', 'Improve appearance', 'B', 'Preheat slows the cooling rate, reducing thermal stress and the risk of hydrogen-induced cracking, especially on thick or high-carbon material.', 'AWS D1.1', 'medium'),
('CW', 'metallurgy', 'The heat-affected zone (HAZ) is:', 'The molten weld metal itself', 'The base metal area altered by welding heat but not melted', 'The area outside the weld', 'The slag layer', 'B', 'The HAZ is the base metal that has been heated below its melting point but high enough to alter its microstructure.', 'AWS A3.0', 'medium'),
('CW', 'visual_inspection', 'A crater crack in a weld must be:', 'Accepted if small', 'Rejected — no cracks are permitted in AWS D1.1', 'Filled with peening', 'Marked but ignored', 'B', 'AWS D1.1 §6.9 prohibits cracks of any size or location. Crater cracks must be removed and re-welded.', 'AWS D1.1 §6.9', 'easy'),
('CW', 'processes', 'In SMAW, the slag covering serves to:', 'Add filler metal', 'Protect the cooling weld and shape the bead', 'Reduce arc voltage', 'Increase travel speed', 'B', 'Slag protects the weld during cooling, slows cooling, and helps shape the bead profile.', 'AWS A3.0', 'easy'),
('CW', 'processes', 'When stick welding, the arc length should normally be:', 'Twice the electrode core diameter', 'Equal to the electrode core diameter', 'As long as possible', 'Zero (touching)', 'B', 'Standard practice is an arc length approximately equal to the electrode core diameter for most SMAW electrodes.', 'AWS D1.1', 'easy'),
('CW', 'safety', 'Welding in a confined space requires:', 'No special precautions', 'Continuous ventilation, air monitoring, and a safety attendant', 'Only a respirator', 'Higher amperage', 'B', 'Confined space welding per OSHA 1910.146 requires continuous ventilation, atmospheric monitoring, an attendant, and rescue capability.', 'OSHA 1910.146', 'medium'),
('CW', 'visual_inspection', 'Spatter on the base metal adjacent to a weld is:', 'Always rejectable', 'Cosmetic only unless code specifies otherwise', 'A sign of porosity', 'Required for good fusion', 'B', 'Spatter is generally cosmetic. Some codes (e.g., D1.1) require its removal but it is not a structural defect.', 'AWS D1.1', 'easy'),
('CW', 'processes', 'For overhead SMAW with E7018, you should use:', 'Higher amperage than flat position', 'Lower amperage than flat position', 'The same amperage as flat', 'Maximum amperage', 'B', 'Overhead welding uses 10-15% lower amperage than flat to keep the molten pool small and manageable against gravity.', 'AWS D1.1', 'medium'),
('CW', 'visual_inspection', 'Incomplete fusion at the root of a groove weld is most often caused by:', 'Excessive heat', 'Insufficient heat input or poor joint preparation', 'Too much shielding gas', 'High humidity', 'B', 'Incomplete root fusion is typically caused by insufficient amperage, fast travel, poor joint fit-up, or improper electrode angle.', 'AWS D1.1', 'medium'),
('CW', 'metallurgy', 'Hot cracking in carbon steel welds is associated with:', 'Sulfur and phosphorus contamination', 'Hydrogen', 'Low carbon', 'Excessive preheat', 'A', 'Hot cracking (solidification cracking) is caused by impurities like sulfur and phosphorus, deep narrow beads, and excessive restraint.', 'AWS D1.1', 'medium'),
('CW', 'processes', 'FCAW (flux-cored) wire that requires no external shielding gas is called:', 'Gas-shielded FCAW', 'Self-shielded FCAW', 'Metal-cored', 'Solid wire', 'B', 'Self-shielded FCAW (FCAW-S) generates its own shielding gas from the flux core, making it ideal for outdoor and field work.', 'AWS A5.20', 'easy'),
('CW', 'processes', 'TIG welding aluminum requires:', 'DCEN', 'DCEP', 'AC with high frequency', 'AC without high frequency', 'C', 'AC TIG with high frequency is required for aluminum to break through the aluminum oxide layer on each cycle.', 'AWS D1.2', 'medium'),
('CW', 'visual_inspection', 'A fillet weld leg size is measured:', 'From the toe to the root', 'From the leg of the weld to the toe', 'Along the face of the weld', 'Diagonally across the throat', 'B', 'Leg size is the perpendicular distance from the joint root to the toe of the fillet weld along each leg.', 'AWS A3.0', 'medium'),
('CW', 'safety', 'Compressed gas cylinders should always be:', 'Stored horizontally', 'Stored vertically and secured', 'Kept in direct sunlight', 'Stored with regulators on', 'B', 'Cylinders must be stored upright, secured against falling, with valve protection caps on when not in use.', 'OSHA 1910.253', 'easy'),
('CW', 'visual_inspection', 'Excessive reinforcement on a groove weld:', 'Improves strength', 'Creates stress concentration and is limited by code', 'Has no effect', 'Is required by AWS D1.1', 'B', 'Excessive reinforcement creates a stress riser at the toes and is limited per AWS D1.1 Table 6.1.', 'AWS D1.1 §6.9', 'medium'),
('CW', 'processes', 'Wire stickout (electrode extension) in MIG affects:', 'Only travel speed', 'Resistance heating and current at the arc', 'Shielding gas flow only', 'Bead color only', 'B', 'Longer stickout increases resistance heating and reduces current at the arc, lowering penetration. Maintain consistent stickout for consistent welds.', 'AWS A3.0', 'medium'),
('CW', 'metallurgy', 'When welding stainless steel, you should NOT use:', 'A clean stainless wire brush', 'A carbon steel wire brush', 'Argon shielding gas', 'A grinder dedicated to stainless', 'B', 'Carbon steel brushes embed iron particles into the stainless surface, causing rust and reducing corrosion resistance.', 'AWS D1.6', 'easy'),
('CW', 'processes', 'In SMAW, "drag technique" means:', 'Push the electrode away from the weld pool', 'Pull the electrode behind the weld pool', 'Hold electrode perpendicular', 'Weave the electrode side to side', 'B', 'Drag (or pull) technique is the standard for SMAW — the electrode is pulled away from the deposited weld with a slight backward angle.', 'AWS D1.1', 'easy'),

